27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
34	
35	const BASE_PREMIUMS: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	
46	const isComponentBlock = (type: string, count: number): boolean =>
47	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
48	
49	const surchargeFor = (
50	  items: Item[],
51	  applies: (item: Item) => boolean,
52	  rate: number
53	): number =>
54	  items.reduce(
55	    (surcharge, item) =>
56	      applies(item) ? surcharge + BASE_PREMIUMS[item.type] * rate : surcharge,
57	    0
58	  );
59	
60	const isCursed = (item: Item): boolean => item.cursed === true;
61	
62	const isHighlyEnchanted = (item: Item): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	const curseSurchargeFor = (items: Item[]): number =>
66	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
67	
68	const enchantmentSurchargeFor = (items: Item[]): number =>
69	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
70	
71	const basePremiumFor = (items: Item[]): number => {
72	  const countsByType = new Map<string, number>();
73	  for (const item of items) {
74	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
75	  }
76	
77	  let basePremium = curseSurchargeFor(items) + enchantmentSurchargeFor(items);
78	  for (const [type, count] of countsByType) {
79	    basePremium += isComponentBlock(type, count)
80	      ? COMPONENT_BLOCK_BASE_PREMIUM
81	      : count * BASE_PREMIUMS[type];
82	  }
83	  return basePremium;
84	};
85	
86	const quotePremium = (items: Item[]): number => {
87	  const basePremium = basePremiumFor(items);
88	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
89	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
90	};
91	
92	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
93	  const items = input.steps[0].items ?? [];
94	  return { results: [{ premium: quotePremium(items) }] };
95	};
